<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Snake</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #1a1a2e;
    color: #eee;
    font-family: 'Segoe UI', system-ui, sans-serif;
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 100vh;
    overflow: hidden;
  }
  .game-container {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 12px;
  }
  #score {
    font-size: 28px;
    font-weight: 700;
    color: #e94560;
    text-shadow: 0 0 10px rgba(233,69,96,.4);
  }
  canvas#snake {
    border: 2px solid #16213e;
    background: #0f3460;
    image-rendering: pixelated;
  }
  .controls {
    display: flex;
    gap: 10px;
  }
  button {
    padding: 8px 20px;
    font-size: 15px;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    font-weight: 600;
    transition: transform .1s, box-shadow .1s;
  }
  button:active { transform: scale(.95); }
  #start { background: #e94560; color: #fff; }
  #pause  { background: #533483; color: #fff; }
  #reset  { background: #16213e; color: #eee; border: 1px solid #0f3460; }
</style>
</head>
<body>

<div class="game-container">
  <div id="score">Score: 0</div>
  <canvas id="snake" width="520" height="520"></canvas>
  <div class="controls">
    <button id="start">Start</button>
    <button id="pause">Pause</button>
    <button id="reset">Reset</button>
  </div>
</div>

<script>
(function () {
  'use strict';

  // ── constants ────────────────────────────────────────────────
  const CELL = 52;                 // pixels per cell (520 / 10)
  const W    = 10;                 // grid width
  const H    = 10;                 // grid height

  // ── DOM refs ─────────────────────────────────────────────────
  const canvas   = document.getElementById('snake');
  const ctx      = canvas.getContext('2d');
  const scoreEl  = document.getElementById('score');
  const startBtn = document.getElementById('start');
  const pauseBtn = document.getElementById('pause');
  const resetBtn = document.getElementById('reset');

  // ── game state ───────────────────────────────────────────────
  let snake, dir, nextDir, food, score, alive, running;

  function init() {
    snake   = [[5,5],[4,5],[3,5]];
    dir     = 'right';
    nextDir = 'right';
    score   = 0;
    alive   = true;
    running = false;
    placeFood();
    draw();
    updateScore();
  }

  function placeFood() {
    const occupied = new Set(snake.map(s => s[0] + ',' + s[1]));
    let x, y, attempts = 0;
    do {
      x = Math.floor(Math.random() * W);
      y = Math.floor(Math.random() * H);
      attempts++;
    } while (occupied.has(x + ',' + y) && attempts < 500);
    food = [x, y];
  }

  function updateScore() {
    scoreEl.textContent = 'Score: ' + score;
  }

  // ── public API on window.game ────────────────────────────────
  window.game = {
    w: W,
    h: H,
    reset: function () { init(); },
    tick: function () { if (alive) step(); },
    setDir: function (d) {
      const opposites = { up:'down', down:'up', left:'right', right:'left' };
      if (opposites[d] !== dir && opposites[d] !== nextDir) {
        nextDir = d;
      }
    },
    setFood: function (x, y) { food = [x, y]; placeFood(); draw(); },
    snake: function () { return snake.map(c => [c[0], c[1]]); },
    food:  function () { return food; },
    alive: function () { return alive; },
    score: function () { return score; }
  };

  // ── core logic ───────────────────────────────────────────────
  function step() {
    if (!alive) return;
    dir = nextDir;
    const head = snake[0];
    const nx   = head[0] + dx[dir];
    const ny   = head[1] + dy[dir];

    // wall collision
    if (nx < 0 || nx >= W || ny < 0 || ny >= H) {
      alive = false;
      running = false;
      draw();
      return;
    }
    // self collision
    for (const seg of snake) {
      if (seg[0] === nx && seg[1] === ny) {
        alive = false;
        running = false;
        draw();
        return;
      }
    }

    const newHead = [nx, ny];
    let ate = (nx === food[0] && ny === food[1]);
    if (!ate) snake.push(snake.pop());
    else { score++; placeFood(); updateScore(); }
    snake.unshift(newHead);
    draw();
  }

  // ── drawing ───────────────────────────────────────────────────
  function draw() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // grid background
    for (let y = 0; y < H; y++)
      for (let x = 0; x < W; x++)
        ctx.fillStyle = '#1a2744';
        ctx.fillRect(x * CELL, y * CELL, CELL, CELL);

    // food
    const fx = food[0] * CELL + CELL / 2;
    const fy = food[1] * CELL + CELL / 2;
    ctx.fillStyle = '#e94560';
    ctx.shadowColor = '#e94560';
    ctx.shadowBlur = 8;
    ctx.beginPath();
    ctx.arc(fx, fy, CELL * 0.35, 0, Math.PI * 2);
    ctx.fill();
    ctx.shadowBlur = 0;

    // snake body (tail → head)
    for (let i = snake.length - 1; i >= 0; i--) {
      const [sx, sy] = snake[i];
      const pad = i === 0 ? 2 : 3;
      ctx.fillStyle = i === 0 ? '#53d769' : '#4caf50';
      if (i === 0) {
        ctx.shadowColor = '#53d769';
        ctx.shadowBlur = 6;
      }
      ctx.fillRect(sx * CELL + pad, sy * CELL + pad, CELL - pad * 2, CELL - pad * 2);
    }
    ctx.shadowBlur = 0;

    // overlay when dead
    if (!alive) {
      ctx.fillStyle = 'rgba(0,0,0,.55)';
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.fillStyle = '#e94560';
      ctx.font = 'bold 32px system-ui';
      ctx.textAlign = 'center';
      ctx.fillText('Game Over', canvas.width / 2, canvas.height / 2 - 10);
    }
  }

  // ── input & loop ─────────────────────────────────────────────
  const dx = { up:0, down:0, left:-1, right:1 };
  const dy = { up:-1, down:1, left:0, right:0 };

  document.addEventListener('keydown', e => {
    if (!['ArrowUp','ArrowDown','ArrowLeft','ArrowRight'].includes(e.key)) return;
    e.preventDefault();
    switch (e.key) {
      case 'ArrowUp':    window.game.setDir('up'); break;
      case 'ArrowDown':  window.game.setDir('down'); break;
      case 'ArrowLeft':  window.game.setDir('left'); break;
      case 'ArrowRight': window.game.setDir('right'); break;
    }
  });

  startBtn.addEventListener('click', () => {
    if (!alive) return;
    running = true;
    gameLoop();
  });
  pauseBtn.addEventListener('click', () => {
    running = false;
  });
  resetBtn.addEventListener('click', () => { init(); });

  function gameLoop() {
    if (running && alive) {
      step();
      setTimeout(gameLoop, 120); // ~8 ticks/sec
    } else if (!alive) {
      running = false;
    }
  }

  // ── bootstrap ────────────────────────────────────────────────
  init();
})();
</script>
</body>
</html>
